mapper.sql:
WHERE 1 = 1
AND q.hospital_id = #{hospitalId}
AND q.id < #{filter.lastWorklistId}
AND ( LOWER(q.visit_code) = LOWER(#{filter.searchText}) OR LOWER(p.patient_uid) = LOWER(#{filter.searchText}) OR p.first_name ILIKE '%' || #{filter.searchText} || '%' OR p.last_name ILIKE '%' || #{filter.searchText} || '%' OR TRIM(CONCAT(COALESCE(p.first_name, ''), ' ', COALESCE(p.last_name, ''))) ILIKE '%' || #{filter.searchText} || '%' OR COALESCE(p.phone_number, '') ILIKE '%' || #{filter.searchText} || '%' OR p.patient_uid ILIKE '%' || #{filter.searchText} || '%' OR q.visit_code ILIKE '%' || #{filter.searchText} || '%' )
AND LOWER(p.patient_uid) = LOWER(#{filter.patientCode})
AND TRIM(CONCAT(COALESCE(p.first_name, ''), ' ', COALESCE(p.last_name, ''))) ILIKE '%' || #{filter.patientName} || '%'
AND LOWER(COALESCE(p.phone_number, '')) = LOWER(#{filter.phoneNumber})
AND LOWER(q.visit_code) = LOWER(#{filter.visitCode})
AND LOWER(q.visit_code) = LOWER(#{filter.worklistNumber})
AND LOWER(q.visit_code) = LOWER(#{filter.accessionNumber})
AND q.modality_id = #{filter.modalityId}
AND q.status = #{filter.statusCode}
AND q.status IN
#{statusCode}
AND COALESCE(q.scheduled_date, CAST(q.created_at AS DATE), CAST(q.created AS DATE)) >= CAST(#{filter.dateFrom} AS DATE)
AND COALESCE(q.scheduled_date, CAST(q.created_at AS DATE), CAST(q.created AS DATE)) <= CAST(#{filter.dateTo} AS DATE)

mapper.select:
SELECT

FROM pacs_worklists q
INNER JOIN hospitals h ON h.id = q.hospital_id
INNER JOIN patients p ON p.id = q.patient_id
LEFT JOIN modalities m ON m.id = q.modality_id


ORDER BY q.id DESC


        LIMIT #{filter.rowsPerPage}


        LIMIT #{filter.rowsPerPage}
        OFFSET #{filter.page}

SELECT COUNT(1)
FROM pacs_worklists q
WHERE q.hospital_id = #{hospitalId}
  AND q.patient_id = #{patientId}
  AND q.modality_id = #{modalityId}
  AND q.status IN (1, 2, 4)

SELECT status
FROM pacs_worklists
WHERE hospital_id = #{hospitalId}
  AND id = #{id}
LIMIT 1
